# ---- new units ----

def tracker(group_state, frozen, now):
    """Main-text 'state of the group stage': one row per group. frozen is
    accepted for signature symmetry with the other units; the table shows
    only current values."""
    rows = []
    for g in group_state:
        top2 = g["rows"][:2]
        if g["played"]:
            standing = "; ".join(f"{r['team']} {r['Pts']}" for r in top2)
        else:
            standing = "--"
        leaders = sorted((r for r in g["rows"] if r["team"] in now),
                         key=lambda r: -now[r["team"]]["advance_KO"])[:2]
        qual = "; ".join(
            f"{r['team']} {_pct(now[r['team']]['advance_KO'])}" for r in leaders)
        rows.append(f"{g['group']} & {g['played']}/{g['total']} & {standing} & {qual} \\\\")
    return (
        "\\begin{table}[!t]\n  \\centering\n"
        "  \\caption{State of the group stage (live edition)}\\label{tab:tracker}\n"
        "  \\begin{footnotesize}\n"
        "  {\\begin{tabular*}{\\textwidth}{@{\\extracolsep{\\fill}} clll}\n"
        "    \\toprule\n"
        "    Group & Played & Standings (top two, real points) & Advance now (top two) \\\\\n"
        "    \\midrule\n    " + "\n    ".join(rows) + "\n"
        "    \\bottomrule\n  \\end{tabular*}}\n  \\end{footnotesize}\n\\end{table}")


def group_box(g_state, results, expectations, frozen, now):
    """Appendix-A living box for one group: unified round-robin matrix with
    actual/prediction results + right-side standing + qual columns."""
    grp = g_state["group"]
    teams = [r["team"] for r in g_state["rows"]]
    exps = {(e["home"], e["away"]): e
            for e in expectations if e.get("group") == grp}
    res_by_match = results["group"]

    if not g_state["played"]:
        qual = "; ".join(f"{t} {_pct(frozen[t]['advance_KO'])}"
                         for t in teams if t in frozen)
        return (f"\\paragraph{{Group {grp} — live.}} No results yet; "
                f"Frozen qualification odds: {qual}.")

    def _sgn(d): return 1 if d > 0 else (-1 if d < 0 else 0)

    # Build round-robin matrix: rows = teams, cols = opponent teams
    # Extra right-side columns: Actual W/D/L/Pts/Qual% | Frozen Qual% | Track A Qual%
    n = len(teams)
    col_spec = "l" + "c" * n + "rrrr"
    header_teams = " & ".join(f"\\tiny {t}" for t in teams)
    header = f" & {header_teams} & \\makecell{{Actual\\\\W/D/L/Pts/Q\\%}} & Q\\%(F) & Q\\%(A) \\\\"

    matrix_rows = []
    for home in teams:
        cells = []
        for away in teams:
            if home == away:
                cells.append("---")
                continue
            e = exps.get((home, away)) or exps.get((away, home))
            if e is None:
                cells.append("?")
                continue
            match_key = str(e["match"])
            res = res_by_match.get(match_key)
            if res:
                # played: actual score + correct/wrong indicator
                if e["home"] == home:
                    score = f"{res[0]}--{res[1]}"
                    pick = e["pick"]
                    correct = _sgn(pick[0] - pick[1]) == _sgn(res[0] - res[1])
                else:
                    score = f"{res[1]}--{res[0]}"
                    pick = e["pick"]
                    correct = _sgn(pick[0] - pick[1]) == _sgn(res[0] - res[1])
                icon = r"$\checkmark$" if correct else r"$\times$"
                cells.append(f"\\textbf{{{score}}}{icon}")
            else:
                # upcoming: Frozen H/D/A prediction
                ph, pd, pa = e["probs_HDA"]
                if e["home"] == home:
                    cells.append(f"\\tiny {_pct(ph)}/{_pct(pd)}/{_pct(pa)}")
                else:
                    cells.append(f"\\tiny {_pct(pa)}/{_pct(pd)}/{_pct(ph)}")

        # right-side standing columns
        row_data = next((r for r in g_state["rows"] if r["team"] == home), {})
        w, d, l = row_data.get("W", 0), row_data.get("D", 0), row_data.get("L", 0)
        pts = row_data.get("Pts", 0)
        qual_a = _pct(now[home]["advance_KO"]) if home in now else "--"
        qual_f = _pct(frozen[home]["advance_KO"]) if home in frozen else "--"
        actual_str = f"{w}/{d}/{l}/{pts}/{qual_a}\\%"
        matrix_rows.append(
            f"\\tiny {home} & " + " & ".join(cells)
            + f" & \\tiny {actual_str} & \\tiny {qual_f}\\% & \\tiny {qual_a}\\% \\\\"
        )

    return (
        f"\\paragraph{{Group {grp} — live ({g_state['played']} of "
        f"{g_state['total']} played).}}\n"
        "\\begin{footnotesize}\n"
        f"\\begin{{tabular}}{{{col_spec}}}\n"
        "\\toprule\n"
        f"{header}\n"
        "\\midrule\n"
        + "\n".join(matrix_rows) + "\n"
        "\\bottomrule\n"
        "\\end{tabular}\n"
        "\\end{footnotesize}"
    )


def survival_unit(frozen, now):
    """Appendix-B 'now' restatement of the stage-by-stage outcome table.
    frozen is intentionally unused: the locked table sits directly above in
    the paper, so only the conditioned values are printed here."""
    teams = sorted(now, key=lambda t: (-now[t]["champion"], -now[t]["advance_KO"]))
    rows = [f"{t} & {_pct(now[t]['advance_KO'])} & {_pct(now[t]['R16'])} & "
            f"{_pct(now[t]['QF'])} & {_pct(now[t]['SF'])} & "
            f"{_pct(now[t]['final'])} & {_pct(now[t]['champion'])} \\\\"
            for t in teams]
    return (
        "\\subsection*{B.live \\quad The same distribution, conditioned on the "
        "results so far}\n"
        "The table restates the stage-reached probabilities of the locked table "
        "above, conditioned on every result revealed to date; the locked table "
        "never changes, so the pair is directly comparable.\n\n"
        "\\begin{footnotesize}\n\\begin{longtable}{lrrrrrr}\n"
        "\\caption{Stage-reached probabilities conditioned on results so far "
        "(live edition)}\\label{tab:live_survival}\\\\\n"
        "\\toprule\nTeam & KO & R16 & QF & SF & Final & Champion \\\\\n\\midrule\n\\endhead\n"
        + "\n".join(rows) + "\n\\bottomrule\n\\end{longtable}\n\\end{footnotesize}")


def two_track_unit(two_track, learning, fig, info_snapshot=None):
    """The live A-vs-B: frozen-track vs learning-track champion odds, the
    largest accumulated drifts, and the per-match performance records.
    info_snapshot: dict from live_inputs.json deltas.summary + source_freshness,
    or None if live_inputs.json was absent at prediction time."""
    if two_track is None:
        return ("\\textit{Two-track live results begin with the first match "
                "whose box score is collected.}")
    teams = sorted(two_track["frozen"], key=lambda t: -two_track["frozen"][t])[:8]
    rows = "\n".join(
        f"{t} & {_pct(two_track['frozen'][t])} & "
        f"{_pct(two_track['learning'].get(t, 0.0))} & "
        f"{100 * (two_track['learning'].get(t, 0.0) - two_track['frozen'][t]):+.1f} \\\\"
        for t in teams)
    drifts = sorted(learning["drift"].items(), key=lambda kv: -abs(kv[1]))[:8]
    drift_rows = "\n".join(f"{t} & {d:+.1f} \\\\" for t, d in drifts)
    pend = (f" Stats pending for matches: "
            f"{', '.join(f'M{m:03d}' for m in learning['pending'])}."
            if learning["pending"] else "")
    fig_block = ("\\begin{figure}[!t]\n  \\caption{Two tracks live: frozen vs "
                 "learning champion paths}\\label{fig:twotracklive}\n"
                 "  {\\centering\\includegraphics[width=0.94\\textwidth]"
                 "{figs/fig_two_track_live.pdf}\\par}\n\\end{figure}\n" if fig else "")
    n = len(learning["processed"])

    return (
        "\\subsection{The two tracks live: 2026 as it speaks}"
          "\\label{sec:twotracklive}\n"
          f"The pre-registered A-vs-B study of Appendix~D, running on the real "
          f"tournament: after each match the observed shot performance "
          f"($\\lambda_{{\\mathrm{{obs}}}}$, Appendix~D.2) updates the learning "
          f"track's ratings (k=50, locked), while the frozen track re-conditions "
          f"on results alone. {n} match(es) processed so far.{pend}\n\n"
        + fig_block
        + "\\begin{footnotesize}\n"
          "\\begin{tabular}{lrrr}\n\\toprule\n"
          "Team & Frozen (\\%) & Track~B (\\%) & $\\Delta$ (pp) \\\\\n\\midrule\n"
        + rows
        + "\n\\bottomrule\n\\end{tabular}\\qquad\n"
          "\\begin{tabular}{lr}\n\\toprule\nTeam & Drift (Elo) \\\\\n\\midrule\n"
        + drift_rows
        + "\n\\bottomrule\n\\end{tabular}\n\\end{footnotesize}"
    )


def _stats_release(match, match_stats, learning):
    s = match_stats.get(match)
    rec = next((r for r in learning["processed"] if r["match"] == match), None)
    if s is None:
        return ("\\textit{Box-score statistics for this match are pending; the "
                "performance analysis will appear in the next edition.}")
    def _row(label, key, fmt="{:.0f}"):
        return (f"{label} & " + fmt.format(s['home'][key]) + " & "
                + fmt.format(s['away'][key]) + " \\\\")
    lines = [_row("Shots", "total_shots"), _row("On target", "sot")]
    if (s["home"].get("possession") is not None
            and s["away"].get("possession") is not None):
        lines.append(_row("Possession (\\%)", "possession", "{:.0f}"))
    perf = ""
    if rec:
        perf = (f"\\\\[2pt] Performance vs.\\ expectation: "
                f"$\\lambda_{{\\mathrm{{obs}}}}$ = {rec['lam_obs']['home']:.2f} / "
                f"{rec['lam_obs']['away']:.2f} against "
                f"$\\lambda_{{\\mathrm{{exp}}}}$ = {rec['lam_exp']['home']:.2f} / "
                f"{rec['lam_exp']['away']:.2f} "
                f"({rec['lam_obs']['source']} signal); the learning track moves "
                f"{rec['home']} by {rec['drift_after'].get(rec['home'], 0):+.1f} and "
                f"{rec['away']} by {rec['drift_after'].get(rec['away'], 0):+.1f} Elo.")
    return ("\\begin{table}[!h]\\centering\n"
            "\\caption{Match statistics (live edition M\\liveEditionNum{})}\\label{tab:live_edition_snapshot}\n"
            "\\begin{footnotesize}\\begin{tabular}{lrr}\\toprule\n"
            f" & {s['home']['team']} & {s['away']['team']} \\\\\n\\midrule\n"
            + "\n".join(lines) + "\n\\bottomrule\\end{tabular}\\end{footnotesize}"
            + perf
            + "\n\\end{table}")


def _cumulative_stats_table(entries, match_stats, expectations):
    """Table 7: one row per played match, grows with each edition.
    Columns: Game | Shots H–A | On target H–A | Poss H–A | Frozen H/D/A."""
    rows = []
    exp_by_match = {e["match"]: e for e in expectations}
    for e in sorted(entries, key=lambda x: x["match"]):
        m = e["match"]
        s = match_stats.get(m)
        if s is None:
            continue
        sh = s["home"].get("total_shots", "--")
        sa = s["away"].get("total_shots", "--")
        oh = s["home"].get("sot", "--")
        oa = s["away"].get("sot", "--")
        ph = s["home"].get("possession")
        pa = s["away"].get("possession")
        poss = f"{ph:.0f}--{pa:.0f}" if ph is not None and pa is not None else "--"
        exp = exp_by_match.get(m)
        if exp:
            hda = "/".join(_pct(p) for p in exp["probs_HDA"])
        else:
            hda = "--"
        rows.append(
            f"M{m} {e['fixture']} & {sh}--{sa} & {oh}--{oa} & {poss} & {hda} \\\\"
        )
    if not rows:
        return r"\textit{Match statistics pending.}"
    return (
        "\\begin{table}[!h]\\centering\n"
        "\\caption{Cumulative match statistics (live edition "
        "M\\liveEditionNum{})}\\label{tab:live_match_stats}\n"
        "\\begin{footnotesize}\\begin{tabular}{lcccc}\\toprule\n"
        "Game & Shots (H--A) & On target (H--A) & Poss\\% (H--A) & Frozen H/D/A \\\\\n"
        "\\midrule\n"
        + "\n".join(rows) + "\n"
        "\\bottomrule\\end{tabular}\\end{footnotesize}\n\\end{table}"
    )


def revision_report(ctx):
    """The central-bank release: data release, forecast revision vs the
    previous edition, implications, vintages. Driver contract: ctx
    vintages_rows already contains THIS edition's row (so [-2] is the
    previous edition) and ctx['match'] equals the latest entry's match."""
    import vintages as vin
    m = ctx["match"]
    latest = max(ctx["entries"], key=lambda e: e["match"])
    deltas = []
    prev, now = ctx["prev_now"], ctx["now"]
    for t in sorted(now, key=lambda t: -now[t]["champion"])[:8]:
        if t in prev:
            d = 100 * (now[t]["champion"] - prev[t]["champion"])
            if abs(d) >= 0.05:
                deltas.append(f"{t} {d:+.1f}")
    delta_line = ("; ".join(deltas) if deltas
                  else "no contender moved by 0.1 pp or more")
    imp_lines = "\n".join(
        f"{i['fixture']} & {'/'.join(_pct(p) for p in i['lock_HDA'])} & "
        f"{'/'.join(_pct(p) for p in i['learn_HDA'])} \\\\"
        for i in ctx["implications"])
    imp_block = ("" if not ctx["implications"] else
        "\\paragraph{Implications for upcoming fixtures.} Frozen odds are the "
        "pre-kickoff baseline (they move only through qualification scenarios); "
        "Track~B odds incorporate live Elo and bookmaker signals.\n"
        "\\begin{footnotesize}\\begin{tabular}{lcc}\\toprule\n"
        "Fixture & Frozen H/D/A (\\%) & Track~B H/D/A (\\%) \\\\\n\\midrule\n"
        + imp_lines + "\n\\bottomrule\\end{tabular}\\end{footnotesize}\n")
    return (
        f"\\subsection{{Revision report: edition M{m:03d}}}\\label{{sec:revreport}}\n"
        f"\\paragraph{{The data release.}} Match {latest['match']}, "
        f"{latest['fixture']}: predicted {latest['pre']['pick'][0]}--"
        f"{latest['pre']['pick'][1]}, actual {latest['result'][0]}--"
        f"{latest['result'][1]}; {latest['post']['points']} of 3 points, Brier "
        f"{latest['post']['brier']:.3f}, {latest['post']['info_bits']:.3f} bits.\n\n"
        + _cumulative_stats_table(
            ctx["entries"], ctx["match_stats"],
            ctx.get("expectations", [])) + "\n\n"
        f"\\paragraph{{Forecast revision (vs.\\ edition M{ctx['vintages_rows'][-2]['edition']:03d}).}} "
        f"Champion-probability movement: {delta_line}.\n\n"
        + imp_block +
        "\\paragraph{Forecast vintages.} One column per issued edition; the "
        "locked M000 column never changes.\n\n"
        + vin.latex_table(ctx["vintages_rows"]))


